+
+        let pane_id = u64::try_from(pane_id_i64).unwrap_or(0);
+        return Ok(Some(event_identity_key(
+            &detection,
+            pane_id,
+            pane_uuid.as_deref(),
+        )));
+    }
+
+    Ok(None)
+}
